detailed_optimizations.code_changes:
将循环顺序从i-k-j改为i-j-k，使C[i][j]在寄存器中累积，减少内存访问次数。

// 优化后代码
for (i = 0; i < _PB_NI; i++) {
  for (j = 0; j < _PB_NJ; j++) {
    DATA_TYPE temp = C[i][j] * beta;
    for (k = 0; k < _PB_NK; k++) {
      temp += alpha * A[i][k] * B[k][j];
    }
    C[i][j] = temp;
  }
}

将循环分块，使每个块的数据能放入缓存。

// 分块参数（根据L1/L2缓存大小调整）
int TILE_I = 64, TILE_J = 64, TILE_K = 64;
for (ii = 0; ii < _PB_NI; ii += TILE_I) {
  for (jj = 0; jj < _PB_NJ; jj += TILE_J) {
    // 初始化C的块
    for (i = ii; i < min(ii+TILE_I, _PB_NI); i++) {
      for (j = jj; j < min(jj+TILE_J, _PB_NJ); j++) {
        C[i][j] *= beta;
      }
    }
    for (kk = 0; kk < _PB_NK; kk += TILE_K) {
      // 计算A和B的块，累加到C的块
      for (i = ii; i < min(ii+TILE_I, _PB_NI); i++) {
        for (k = kk; k < min(kk+TILE_K, _PB_NK); k++) {
          DATA_TYPE a_ik = A[i][k];
          for (j = jj; j < min(jj+TILE_J, _PB_NJ); j++) {
            C[i][j] += alpha * a_ik * B[k][j];
          }
        }
      }
    }
  }
}

在最内层j循环使用SIMD指令并行处理多个元素。

// 使用OpenMP SIMD指令
#pragma omp simd
for (j = 0; j < _PB_NJ; j++) {
  C[i][j] += alpha * A[i][k] * B[k][j];
}

// 或使用编译器特定的向量化提示（如GCC的__builtin_assume_aligned）

使用posix_memalign或_aligned_malloc分配对齐的内存，并调整循环边界。

// 分配对齐的内存
DATA_TYPE* A_aligned;
posix_memalign((void**)&A_aligned, 64, NI * NK * sizeof(DATA_TYPE));

// 在循环中使用restrict关键字避免指针别名
void kernel_gemm(..., DATA_TYPE* restrict C, ...)
